Rule.Source:
 
  import sailpoint.object.ProvisioningPlan;
  import sailpoint.object.ProvisioningPlan.AccountRequest;
  import sailpoint.tools.Util;
  import connector.common.JsonUtil;
  import connector.common.Util;
  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;

  Log logger = LogFactory.getLog("rule.Ascension.Voalte.create.BeforeOperation");

  String sessionVal = createSession();
  String sessionToken = "VoalteSession "+sessionVal;

  List requestedClientAccess=new ArrayList();
  if (provisioningPlan != null) {
    for (AccountRequest accReq : Util.iterate(provisioningPlan.getAccountRequests())) {
      if(accReq!=null) {
        for (ProvisioningPlan.AttributeRequest attReq : Util.iterate(accReq.getAttributeRequests())) {
          if(attReq!=null) {
            String attrName = attReq.getName();
            if (attrName != null && "client_type_access".equalsIgnoreCase(attrName)) {
              if(attReq.getValue() instanceof String){
                requestedClientAccess.add(attReq.getValue());
              }else{
                requestedClientAccess= attReq.getValue();
              }
            }
          }
        }
      }
    }
  } 
  try{
    Map body = requestEndPoint.getBody();

    String jsonBody = (String) body.get("jsonBody");
    List accessList = new ArrayList();

    Map jsonMap = JsonUtil.toMap(jsonBody);
    if (jsonMap != null) {
      Object accessType = jsonMap.get("client_type_access");

      accessList.add("voalte_messenger");
      if(requestedClientAccess!=null && !requestedClientAccess.isEmpty() && requestedClientAccess.contains("voalte_me")){
        accessList.add("voalte_me");
      }

      jsonMap.remove("client_type_access");
      jsonMap.put("client_type_access", accessList);

      String finalBody = JsonUtil.render(jsonMap);
      body.put("jsonBody", finalBody);
      requestEndPoint.setBody(body);
    }

    Map headerMap = requestEndPoint.getHeader();
    headerMap.put("Authorization",sessionToken);
    requestEndPoint.setHeader(headerMap);

  }catch(Exception e) {
    logger.error("Exception in NetSuite aggregation before rule "+e.getMessage());
  }

  return requestEndPoint;
